t.script:
document.addEventListener('DOMContentLoaded', function() {
    const tabs = document.querySelectorAll('.ae-filter-tab');
    const contentArea = document.querySelector('.ae-dynamic-content');

    if (!tabs.length || !contentArea) return;

    tabs.forEach(tab => {
        tab.addEventListener('click', function(e) {
            e.preventDefault();
            const url = this.getAttribute('href');

            // Highlight active tab
            tabs.forEach(t => t.classList.remove('ae-tab-active'));
            this.classList.add('ae-tab-active');

            // Fade out gracefully
            contentArea.style.opacity = '0.5';

            // Build fetch URL
            const sep = url.includes('?') ? '&' : '?';
            const fetchUrl = url + sep + 'ajax=1';

            fetch(fetchUrl)
                .then(response => response.text())
                .then(html => {
                    contentArea.innerHTML = html;
                    contentArea.style.opacity = '1';
                    window.history.pushState({path: url}, '', url);
                })
                .catch(err => {
                    console.error('Error fetching partial:', err);
                    window.location.href = url; // fallback
                });
        });
    });

    // Handle browser back/forward buttons
    window.addEventListener('popstate', function(e) {
        window.location.reload();
    });
});
